from __future__ import annotations

import io
import os
import json
import threading
from collections import Counter, defaultdict
from dataclasses import dataclass, asdict
from typing import Dict, List, Optional, Any, Tuple

from flask import Flask, request, jsonify, send_file
from PIL import Image
import numpy as np

try:
    import torch
    import torch.nn as nn
    import torch.optim as optim
    from torch.utils.data import Dataset, DataLoader
    from torchvision import models, transforms
except Exception as e:
    raise RuntimeError("PyTorch and torchvision are required to run this application.") from e


app = Flask(__name__)

DATA_DIR = os.environ.get("LABELING_DATA_DIR", "./labeling_data")
IMAGES_DIR = os.path.join(DATA_DIR, "images")
os.makedirs(IMAGES_DIR, exist_ok=True)

lock = threading.Lock()


@dataclass
class Annotation:
    annotator_id: str
    label: str


@dataclass
class ImageRecord:
    image_id: str
    filename: str
    annotations: List[Annotation]
    consensus_label: Optional[str] = None


class LabelStore:
    def __init__(self) -> None:
        self.records: Dict[str, ImageRecord] = {}
        self.next_id = 1

    def add_image(self, image_bytes: bytes, filename: str) -> str:
        image_id = str(self.next_id)
        self.next_id += 1
        safe_filename = f"{image_id}_{os.path.basename(filename)}"
        path = os.path.join(IMAGES_DIR, safe_filename)
        with open(path, "wb") as f:
            f.write(image_bytes)
        self.records[image_id] = ImageRecord(
            image_id=image_id,
            filename=safe_filename,
            annotations=[],
            consensus_label=None,
        )
        return image_id

    def add_annotation(self, image_id: str, annotator_id: str, label: str) -> None:
        if image_id not in self.records:
            raise KeyError("image_id not found")
        self.records[image_id].annotations.append(Annotation(annotator_id=annotator_id, label=label))
        self.records[image_id].consensus_label = self.majority_vote(image_id)

    def majority_vote(self, image_id: str) -> Optional[str]:
        record = self.records[image_id]
        if not record.annotations:
            return None
        counts = Counter(a.label for a in record.annotations)
        top = counts.most_common()
        if not top:
            return None
        max_count = top[0][1]
        winners = [label for label, count in top if count == max_count]
        return sorted(winners)[0]

    def labeled_records(self) -> List[Tuple[str, str]]:
        out = []
        for image_id, record in self.records.items():
            label = record.consensus_label
            if label is not None:
                out.append((os.path.join(IMAGES_DIR, record.filename), label))
        return out

    def to_dict(self) -> Dict[str, Any]:
        return {
            image_id: {
                "image_id": rec.image_id,
                "filename": rec.filename,
                "annotations": [asdict(a) for a in rec.annotations],
                "consensus_label": rec.consensus_label,
            }
            for image_id, rec in self.records.items()
        }


store = LabelStore()


def save_state() -> None:
    state_path = os.path.join(DATA_DIR, "state.json")
    with lock:
        with open(state_path, "w", encoding="utf-8") as f:
            json.dump(store.to_dict(), f, indent=2)


def load_state() -> None:
    state_path = os.path.join(DATA_DIR, "state.json")
    if not os.path.exists(state_path):
        return
    with open(state_path, "r", encoding="utf-8") as f:
        data = json.load(f)
    with lock:
        store.records.clear()
        max_id = 0
        for image_id, rec in data.items():
            annotations = [Annotation(**a) for a in rec.get("annotations", [])]
            store.records[image_id] = ImageRecord(
                image_id=rec["image_id"],
                filename=rec["filename"],
                annotations=annotations,
                consensus_label=rec.get("consensus_label"),
            )
            try:
                max_id = max(max_id, int(image_id))
            except Exception:
                pass
        store.next_id = max_id + 1


class LabeledImageDataset(Dataset):
    def __init__(self, items: List[Tuple[str, str]], label_to_idx: Dict[str, int]) -> None:
        self.items = items
        self.label_to_idx = label_to_idx
        self.transform = transforms.Compose(
            [
                transforms.Resize((224, 224)),
                transforms.ToTensor(),
                transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
            ]
        )

    def __len__(self) -> int:
        return len(self.items)

    def __getitem__(self, idx: int) -> Tuple[torch.Tensor, int]:
        path, label = self.items[idx]
        img = Image.open(path).convert("RGB")
        x = self.transform(img)
        y = self.label_to_idx[label]
        return x, y


def create_model(num_classes: int) -> nn.Module:
    model = models.resnet18(weights=None)
    model.fc = nn.Linear(model.fc.in_features, num_classes)
    return model


def train_model(epochs: int = 3, batch_size: int = 16, lr: float = 1e-3) -> Dict[str, Any]:
    items = store.labeled_records()
    if not items:
        raise ValueError("No labeled data available for training.")
    labels = sorted({label for _, label in items})
    label_to_idx = {label: i for i, label in enumerate(labels)}
    dataset = LabeledImageDataset(items, label_to_idx)
    loader = DataLoader(dataset, batch_size=batch_size, shuffle=True, num_workers=0)
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model = create_model(len(labels)).to(device)
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=lr)

    model.train()
    for epoch in range(epochs):
        running_loss = 0.0
        total = 0
        for x, y in loader:
            x = x.to(device)
            y = y.to(device)
            optimizer.zero_grad()
            logits = model(x)
            loss = criterion(logits, y)
            loss.backward()
            optimizer.step()
            running_loss += loss.item() * x.size(0)
            total += x.size(0)

    model_dir = os.path.join(DATA_DIR, "model")
    os.makedirs(model_dir, exist_ok=True)
    model_path = os.path.join(model_dir, "model.pt")
    meta_path = os.path.join(model_dir, "labels.json")
    torch.save(model.state_dict(), model_path)
    with open(meta_path, "w", encoding="utf-8") as f:
        json.dump({"labels": labels}, f, indent=2)
    return {"status": "trained", "model_path": model_path, "labels": labels}


@app.route("/images", methods=["POST"])
def upload_image():
    if "image" not in request.files:
        return jsonify({"error": "missing image file"}), 400
    file = request.files["image"]
    image_bytes = file.read()
    if not image_bytes:
        return jsonify({"error": "empty image"}), 400
    try:
        Image.open(io.BytesIO(image_bytes)).verify()
    except Exception:
        return jsonify({"error": "invalid image"}), 400
    filename = file.filename or "image.jpg"
    with lock:
        image_id = store.add_image(image_bytes, filename)
        save_state()
    return jsonify({"image_id": image_id})


@app.route("/annotations", methods=["POST"])
def add_annotation():
    data = request.get_json(force=True, silent=True) or {}
    image_id = str(data.get("image_id", ""))
    annotator_id = str(data.get("annotator_id", ""))
    label = str(data.get("label", ""))
    if not image_id or not annotator_id or not label:
        return jsonify({"error": "image_id, annotator_id, and label are required"}), 400
    with lock:
        try:
            store.add_annotation(image_id, annotator_id, label)
            save_state()
        except KeyError:
            return jsonify({"error": "image_id not found"}), 404
    return jsonify({"image_id": image_id, "consensus_label": store.records[image_id].consensus_label})


@app.route("/images/<image_id>", methods=["GET"])
def get_image(image_id: str):
    rec = store.records.get(image_id)
    if rec is None:
        return jsonify({"error": "image_id not found"}), 404
    path = os.path.join(IMAGES_DIR, rec.filename)
    if not os.path.exists(path):
        return jsonify({"error": "file not found"}), 404
    return send_file(path, mimetype="image/jpeg")


@app.route("/images/<image_id>/labels", methods=["GET"])
def get_labels(image_id: str):
    rec = store.records.get(image_id)
    if rec is None:
        return jsonify({"error": "image_id not found"}), 404
    return jsonify(
        {
            "image_id": image_id,
            "annotations": [asdict(a) for a in rec.annotations],
            "consensus_label": rec.consensus_label,
        }
    )


@app.route("/dataset", methods=["GET"])
def dataset_summary():
    with lock:
        labeled = store.labeled_records()
        counts = Counter(label for _, label in labeled)
    return jsonify(
        {
            "num_images": len(store.records),
            "num_labeled": len(labeled),
            "label_counts": dict(counts),
        }
    )


@app.route("/train", methods=["POST"])
def train_endpoint():
    data = request.get_json(force=True, silent=True) or {}
    epochs = int(data.get("epochs", 3))
    batch_size = int(data.get("batch_size", 16))
    lr = float(data.get("lr", 1e-3))
    try:
        result = train_model(epochs=epochs, batch_size=batch_size, lr=lr)
        return jsonify(result)
    except Exception as e:
        return jsonify({"error": str(e)}), 400


@app.route("/state", methods=["GET"])
def get_state():
    return jsonify(store.to_dict())


if __name__ == "__main__":
    load_state()
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", "8000")), debug=False)